package ua.university.sms.service;import org.junit.jupiter.api.*;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.boot.test.context.SpringBootTest;import ua.university.sms.model.dto.StudentDtos;import ua.university.sms.model.entity.StudentStatus;import static org.junit.jupiter.api.Assertions.*;
@SpringBootTest class StudentServiceTest{@Autowired StudentService service;@Test void createAndGetStudent(){var s=service.create(new StudentDtos.Request("Test Student","test.student@uni.test",2,StudentStatus.ACTIVE));assertNotNull(s.id());assertEquals("Test Student",service.get(s.id()).fullName());}@Test void filterByStatus(){assertFalse(service.list(StudentStatus.ACTIVE,null,null).isEmpty());}@Test void searchByEmail(){assertFalse(service.list(null,null,"student1").isEmpty());}@Test void topStudentsWorks(){assertFalse(service.top(3).isEmpty());}}
